#!/usr/bin/env bash
# evidence.sh — Evidence 决策助手 for 个人投资理财.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="个人投资理财"
TOPIC="Evidence"

usage() {
  cat <<EOF
evidence.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 5 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./evidence.sh             # interactive
  ./evidence.sh --dry-run   # walk through but no file
  ./evidence.sh --json      # JSON to stdout
  ./evidence.sh --explain   # show backing playbook rules + mental models
  ./evidence.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Evidence 主题下的 playbook 规则组合成交互树。

基于 5 条规则:
  • 如果 你面对「要不要现在买/卖」的择时冲动 → 则 把它自动化、不留人为裁量口——设自动定投（工资到账即扣）、用新供款定向投欠配资产来再平衡。案例：有一笔年终奖迟迟不入场等
  • 如果 组合权重偏离了预设规则 → 则 机械执行再平衡、没触发就不动——日历法（每年固定一天）或阈值法（Swedroe 5/25 规则：绝对偏离 5pp 或相对
  • 如果 你要建一笔交易/仓位 → 则 先定「这笔最多承担多少风险/占多少」再选标的——先 position sizing 后选品：由「入场价−止损价」+ 单笔
  • 如果 你怕自己在市场高/低点乱动 → 则 提前把决策规则写成成文 IPS（投资政策声明）+ 熊市预案，在情绪点拿出来执行而非临场判断。案例：2022 股债双杀时半
  • 如果 你有一整笔闲钱要投 → 则 默认 lump-sum（time-in-market，历史多数区间期望回报 > 把同一笔钱分期 DCA），但按你的损失厌

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "你面对「要不要现在买/卖」的择时冲动"
  "组合权重偏离了预设规则"
  "你要建一笔交易/仓位"
  "你怕自己在市场高/低点乱动"
  "你有一整笔闲钱要投"
)
declare -a RULE_ACTIONS=(
  "把它自动化、不留人为裁量口——设自动定投（工资到账即扣）、用新供款定向投欠配资产来再平衡。案例：有一笔年终奖迟迟不入场等「跌了再买」→ 踏空（市场最佳日紧贴最差日）；改成立即按计划投 + 后续自动定投。evidence: [T03-S005, T01-S026]"
  "机械执行再平衡、没触发就不动——日历法（每年固定一天）或阈值法（Swedroe 5/25 规则：绝对偏离 5pp 或相对偏离 25% 先到者触发）。案例：目标 60/40 牛市后滚到 72/28 → 按 5/25 触发，卖股买债拉回，纪律化低买高卖。evidence: [T03-S006, T01-S008]"
  "先定「这笔最多承担多少风险/占多少」再选标的——先 position sizing 后选品：由「入场价−止损价」+ 单笔最大可亏比例（如总资金 1%）反推股数。案例：固定金额梭哈一只止损宽的标的 → 实际风险敞口爆表，一笔爆仓；改成按风险反推仓位让每笔敞口一致。evidence: [T03-S023, T03-S014]"
  "提前把决策规则写成成文 IPS（投资政策声明）+ 熊市预案，在情绪点拿出来执行而非临场判断。案例：2022 股债双杀时半夜想清仓 → 拿出预先写好的「跌 X% 我继续定投/再平衡」当行为锚，避免在底部锁死亏损。evidence: [T03-S001, T01-S005]"
  "默认 lump-sum（time-in-market，历史多数区间期望回报 > 把同一笔钱分期 DCA），但按你的损失厌恶程度可用 DCA 降后悔。案例：怕一次性投完就遇大跌后悔 → 接受「DCA 期望略低但情绪可控」，分 3-6 个月投入；纯靠工资投本就是天然定投。evidence: [T03-S005, T04-S003]"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "evidence-decision"
fi
